UPDATE t_article
SET favorite_count = favorite_count - #{decrementNum}
WHERE id = #{articleId}
  AND favorite_count >= #{decrementNum}

UPDATE  t_article
SET favorite_count = favorite_count + #{incrementNum}
WHERE id = #{articleId}

UPDATE  t_article
SET view_count = view_count + #{incrementNum}
WHERE id = #{articleId}
